) AS v(ctx_id, fam_code, dom_code, role_code, c0, c1, c2, c3, c4, c5, c6, c7, c8, c9, c10, c11, c12, c13, c14, c15, c16, c17, c18)
JOIN public.role r ON r.code = v.role_code
JOIN public.role_families rf ON rf.code = v.fam_code
JOIN public.domains d ON d.code = v.dom_code
JOIN public.industry_domains idm ON idm.domain_id = d.id
JOIN public.role_family_domains rfd ON rfd.role_family_id = rf.id AND rfd.industry_domain_id = idm.id
